-- Excel exercises migration: India_Fitness_150 + Strength_100_AllMuscles

INSERT INTO exercises (
  name, body_part, equipment, target_muscle,
  secondary_muscles, instructions, exercise_type,
  gif_url, image_url, category, difficulty, is_custom, created_by
) VALUES
  ('barbell bench press', 'chest', 'barbell', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.', 'Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.', 'Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.', 'Lower the barbell slowly towards your chest, keeping your elbows tucked in.', 'Pause for a moment when the barbell touches your chest.', 'Push the barbell back up to the starting position by extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell incline bench press', 'chest', 'barbell', 'pectorals', ARRAY['shoulders', 'triceps'], ARRAY['Set up an incline bench at a 45-degree angle.', 'Lie down on the bench with your feet flat on the ground.', 'Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.', 'Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.', 'Pause for a moment at the bottom, then push the barbell back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell decline bench press', 'chest', 'barbell', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Lie on a decline bench with your feet secured and your head lower than your hips.', 'Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.', 'Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.', 'Pause for a moment at the bottom, then push the barbell back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell bench press', 'chest', 'dumbbell', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.', 'Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest.', 'Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.', 'Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell fly', 'chest', 'dumbbell', 'pectorals', ARRAY['shoulders'], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.', 'Extend your arms straight up over your chest, with a slight bend in your elbows.', 'Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.', 'Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('push-up', 'chest', 'body weight', 'pectorals', ARRAY['triceps', 'deltoids', 'core'], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.', 'Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line.', 'Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('chest dip', 'chest', 'body weight', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Position yourself on parallel bars with your arms fully extended and your body straight.', 'Lower your body by bending your elbows until your shoulders are below your elbows.', 'Push yourself back up to the starting position by straightening your arms.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell incline bench press', 'chest', 'dumbbell', 'pectorals', ARRAY['shoulders', 'triceps'], ARRAY['Set up an incline bench at a 45-degree angle.', 'Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.', 'Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.', 'Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.', 'Push the dumbbells back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('pull-up', 'back', 'body weight', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Hang from a pull-up bar with your palms facing away from you and your arms fully extended.', 'Engage your core and squeeze your shoulder blades together.', 'Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.', 'Pause at the top of the movement, then slowly lower your body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell bent over row', 'back', 'barbell', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.', 'Bend forward at the hips while keeping your back straight and chest up.', 'Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.', 'Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.', 'Pause for a moment at the top, then slowly lower the barbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell one arm bent-over row', 'back', 'dumbbell', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.', 'Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.', 'Let the dumbbell hang straight down towards the floor, with your arm fully extended.', 'Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.', 'Repeat for the desired number of repetitions, then switch sides.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell deadlift', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Stand with your feet shoulder-width apart and the barbell on the ground in front of you.', 'Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.', 'Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.', 'As you stand up straight, squeeze your glutes and keep your core engaged.', 'Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable pulldown', 'back', 'cable', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured.', 'Sit on the seat with your back straight and your feet flat on the ground.', 'Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.', 'Lean back slightly and engage your core.', 'Pull the cable bar down towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('chin-up', 'back', 'body weight', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.', 'Engage your core and pull your body up towards the bar, leading with your chest.', 'Continue pulling until your chin is above the bar.', 'Pause for a moment at the top, then slowly lower your body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell shrug', 'back', 'barbell', 'traps', ARRAY['shoulders'], ARRAY['Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.', 'Keep your arms straight and your back straight throughout the exercise.', 'Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.', 'Hold for a moment, then slowly lower your shoulders back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable seated row', 'back', 'cable', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.', 'Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed.', 'Pull the handles towards your body, squeezing your shoulder blades together.', 'Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell romanian deadlift', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Stand with your feet shoulder-width apart and your toes pointing forward.', 'Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.', 'Bend at the hips, keeping your back straight and your knees slightly bent.', 'Lower the barbell towards the ground, keeping it close to your body.', 'Feel the stretch in your hamstrings as you lower the barbell.', 'Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.', 'Squeeze your glutes at the top of the movement.', 'Lower the barbell back down to the starting position and repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell seated overhead press', 'shoulders', 'barbell', 'delts', ARRAY['triceps', 'upper back'], ARRAY['Sit on a bench with your back straight and feet flat on the ground.', 'Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.', 'Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.', 'Press the barbell overhead by extending your arms fully.', 'Pause for a moment at the top, then slowly lower the barbell back to shoulder level.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell lateral raise', 'shoulders', 'dumbbell', 'delts', ARRAY['traps'], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.', 'Keep your back straight and engage your core.', 'Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.', 'Pause for a moment at the top, then slowly lower your arms back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell front raise', 'shoulders', 'dumbbell', 'delts', ARRAY['biceps', 'trapezius'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.', 'Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.', 'Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell rear lateral raise', 'shoulders', 'dumbbell', 'delts', ARRAY['traps', 'rhomboids'], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.', 'Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged.', 'Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.', 'Pause for a moment at the top, then slowly lower your arms back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell upright row', 'shoulders', 'barbell', 'delts', ARRAY['traps', 'biceps'], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.', 'Let the barbell hang in front of your thighs, arms fully extended.', 'Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.', 'Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell arnold press', 'shoulders', 'dumbbell', 'delts', ARRAY['triceps', 'upper chest'], ARRAY['Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.', 'Press the dumbbells upward until your arms are fully extended and your palms are facing forward.', 'Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement.', 'Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell curl', 'upper arms', 'barbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.', 'Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.', 'Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale as you slowly begin to lower the bar back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell biceps curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.', 'Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly begin to lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell hammer curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your torso.', 'Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.', 'This will be your starting position.', 'Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Then, inhale and slowly begin to lower the dumbbells back to the starting position.', 'Repeat for the recommended amount of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell lying triceps extension', 'upper arms', 'barbell', 'triceps', ARRAY['shoulders'], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.', 'Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.', 'Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.', 'Pause for a moment at the bottom, then extend your arms back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('triceps dip', 'upper arms', 'body weight', 'triceps', ARRAY['chest', 'shoulders'], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.', 'Slide your butt off the bench, supporting your weight with your hands.', 'Bend your elbows and lower your body towards the ground, keeping your back close to the bench.', 'Pause for a moment at the bottom, then push yourself back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable pushdown', 'upper arms', 'cable', 'triceps', ARRAY['forearms'], ARRAY['Attach a straight bar to a high pulley cable machine.', 'Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.', 'Grasp the bar with an overhand grip, hands shoulder-width apart.', 'Keep your elbows close to your sides and your upper arms stationary.', 'Exhale and push the bar down until your elbows are fully extended.', 'Pause for a moment, then inhale and slowly return the bar to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell concentration curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh.', 'Fully extend your arm and hold the dumbbell with an underhand grip.', 'Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps.', 'Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly lower the dumbbell back to the starting position.', 'Repeat for the desired number of repetitions, then switch arms.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell full squat', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves', 'core'], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.', 'Hold the barbell across your upper back, resting it on your traps or rear delts.', 'Engage your core and keep your chest up as you begin to lower your body down.', 'Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.', 'Lower yourself until your thighs are parallel to the ground or slightly below.', 'Keep your knees in line with your toes and your weight in your heels.', 'Drive through your heels to stand back up, extending your hips and knees.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell lunge', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.', 'Take a step forward with your right foot, keeping your torso upright.', 'Lower your body by bending your right knee until your thigh is parallel to the ground.', 'Push through your right heel to return to the starting position.', 'Repeat with your left leg, alternating legs for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever leg extension', 'upper legs', 'machine', 'quads', ARRAY['hamstrings'], ARRAY['Adjust the seat height and backrest of the machine to fit your body.', 'Sit on the machine with your back against the backrest and your feet on the footpad.', 'Grasp the handles or sidebars for stability.', 'Extend your legs forward by straightening your knees, lifting the weight.', 'Pause for a moment at the top, then slowly lower the weight back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever lying leg curl', 'upper legs', 'machine', 'hamstrings', ARRAY['calves'], ARRAY['Adjust the machine to fit your body and select the desired weight.', 'Lie face down on the machine with your legs straight and your heels against the padded lever.', 'Grasp the handles or the sides of the machine for stability.', 'Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad.', 'Hold the contracted position for a brief pause as you squeeze your hamstrings.', 'Inhale and slowly lower the lever back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell single leg deadlift', 'upper legs', 'dumbbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Stand with your feet hip-width apart, holding a dumbbell in your right hand.', 'Shift your weight onto your left leg and lift your right foot slightly off the ground.', 'Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.', 'At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.', 'Lower the dumbbell until your torso and right leg are parallel to the ground.', 'Pause for a moment, then engage your glutes and hamstrings to return to the starting position.', 'Repeat for the desired number of repetitions, then switch sides.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell sumo deadlift', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'quadriceps', 'lower back'], ARRAY['Stand with your feet wider than shoulder-width apart, toes pointing outwards.', 'Place a barbell on the ground in front of you, centered between your feet.', 'Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.', 'Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.', 'As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.', 'Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell hack squat', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing with your feet shoulder-width apart and your toes slightly turned out.', 'Hold the barbell behind your legs, resting it on your upper thighs.', 'Lower your body by bending at the knees and hips, keeping your back straight and your chest up.', 'Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.', 'Pause for a moment, then push through your heels to return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell step-up', 'upper legs', 'dumbbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.', 'Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.', 'Push through your right heel and lift your body up onto the bench or step, straightening your right leg.', 'Bring your left foot up onto the bench or step, standing fully upright.', 'Step back down with your left foot, followed by your right foot, returning to the starting position.', 'Repeat for the desired number of repetitions, then switch legs.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell rear lunge', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.', 'Take a step backward with your right foot, landing on the ball of your foot.', 'Bend both knees to lower your body until your left thigh is parallel to the ground.', 'Push through your left heel to return to the starting position.', 'Repeat with the other leg.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell glute bridge', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.', 'Place a barbell across your hips, holding it securely with both hands.', 'Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.', 'Pause for a moment at the top, squeezing your glutes.', 'Slowly lower your hips back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('crunch floor', 'waist', 'body weight', 'abs', ARRAY['hip flexors'], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.', 'Place your hands behind your head with your elbows pointing outwards.', 'Engage your abs and lift your shoulders off the ground, curling forward towards your knees.', 'Pause for a moment at the top, then slowly lower your shoulders back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('hanging leg raise', 'waist', 'body weight', 'abs', ARRAY['hip flexors'], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.', 'Engage your core and lift your legs up in front of you, keeping them straight.', 'Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.', 'Pause for a moment at the top, then slowly lower your legs back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('russian twist', 'waist', 'body weight', 'abs', ARRAY['obliques'], ARRAY['Sit on the ground with your knees bent and feet flat on the floor.', 'Lean back slightly while keeping your back straight and your core engaged.', 'Hold your hands together in front of your chest or hold a weight if desired.', 'Lift your feet off the ground, balancing on your sit bones.', 'Twist your torso to the right, bringing your hands or weight towards the right side of your body.', 'Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body.', 'Continue alternating sides for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable kneeling crunch', 'waist', 'cable', 'abs', ARRAY['obliques'], ARRAY['Attach a rope handle to a high pulley and kneel down facing away from the machine.', 'Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides.', 'Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs.', 'Pause for a moment at the bottom, then slowly return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('decline crunch', 'waist', 'body weight', 'abs', ARRAY['hip flexors'], ARRAY['Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle.', 'Place your hands behind your head or across your chest.', 'Engage your abs and lift your upper body towards your knees, curling your torso.', 'Pause for a moment at the top, then slowly lower your upper body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('weighted crunch', 'waist', 'body weight', 'abs', ARRAY['obliques'], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.', 'Hold a weight plate or dumbbell on your chest.', 'Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground.', 'Pause for a moment at the top, then slowly lower your upper body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell side bent v. 2', 'waist', 'barbell', 'abs', ARRAY['obliques', 'lower back'], ARRAY['Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.', 'Keep your back straight and core engaged throughout the exercise.', 'Slowly bend your torso to the right side, lowering the barbell towards your right knee.', 'Pause for a moment, then return to the starting position.', 'Repeat the movement on the left side.', 'Continue alternating sides for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dead bug', 'waist', 'body weight', 'abs', ARRAY['hip flexors', 'lower back'], ARRAY['Lie flat on your back with your arms extended towards the ceiling.', 'Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees.', 'Engage your core and lower back to press your lower back into the ground.', 'Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor.', 'Pause for a moment, then return to the starting position.', 'Repeat the movement with your left arm and right leg.', 'Continue alternating sides for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell press sit-up', 'waist', 'barbell', 'abs', ARRAY['shoulders', 'chest'], ARRAY['Lie flat on your back on a mat with your knees bent and feet flat on the ground.', 'Hold the barbell with an overhand grip, resting it on your chest.', 'Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.', 'Pause for a moment at the top, then slowly lower your upper body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell seated twist', 'waist', 'barbell', 'abs', ARRAY['obliques', 'lower back'], ARRAY['Sit on a flat bench with your feet flat on the ground and your knees bent.', 'Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.', 'Engage your core and slowly twist your torso to one side, keeping your back straight.', 'Pause for a moment at the end of the twist, then slowly rotate back to the starting position.', 'Repeat the twist to the other side.', 'Continue alternating sides for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL)
ON CONFLICT DO NOTHING;

INSERT INTO exercises (
  name, body_part, equipment, target_muscle,
  secondary_muscles, instructions, exercise_type,
  gif_url, image_url, category, difficulty, is_custom, created_by
) VALUES
  ('run', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing upright with your feet hip-width apart.', 'Engage your core and keep your upper body relaxed.', 'Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.', 'Maintain a steady pace and continue jogging for the desired duration or distance.', 'Remember to breathe deeply and maintain good posture throughout the exercise.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('stationary bike run v. 3', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Adjust the seat height and position to ensure proper alignment.', 'Place your feet on the pedals and secure them with the straps if available.', 'Start pedaling at a comfortable pace.', 'Maintain a steady rhythm and increase the resistance as desired.', 'Engage your core muscles to maintain stability and proper posture.', 'Continue pedaling for the desired duration of your workout.', 'Gradually decrease the resistance and slow down before coming to a complete stop.', 'Stretch your legs and cool down after the workout.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('walk elliptical cross trainer', 'cardio', 'machine', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Adjust the resistance level and incline of the elliptical machine to your desired settings.', 'Step onto the pedals of the machine and grip the handles lightly.', 'Begin by pushing down with your feet and pulling the handles towards your body.', 'Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion.', 'Maintain a steady pace and keep your core engaged throughout the exercise.', 'Continue for the desired duration of your cardio workout.', 'Gradually decrease the intensity and speed of the machine before stepping off.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('walking on incline treadmill', 'cardio', 'machine', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Adjust the incline level on the treadmill to your desired intensity.', 'Stand on the treadmill with your feet shoulder-width apart.', 'Start walking at a comfortable pace, ensuring that you maintain proper form.', 'Engage your core muscles and keep your back straight throughout the exercise.', 'Continue walking on the incline treadmill for the desired duration of your cardio workout.', 'Gradually decrease the incline and speed of the treadmill to cool down before stopping.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('walking on stepmill', 'cardio', 'machine', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Adjust the stepmill machine to a comfortable level.', 'Step onto the machine and place your hands on the handrails for support.', 'Start walking by placing one foot on a step and then the other, alternating between legs.', 'Maintain an upright posture and engage your core muscles.', 'Continue walking for the desired duration or distance.', 'Gradually increase the intensity or speed as you become more comfortable with the exercise.', 'Remember to cool down and stretch after completing the exercise.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('cycle cross trainer', 'cardio', 'machine', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes'], ARRAY['Adjust the seat height and position yourself on the cycle cross trainer.', 'Place your feet on the pedals and grip the handlebars.', 'Start pedaling in a smooth and controlled motion.', 'Maintain a steady pace and increase the resistance if desired.', 'Continue pedaling for the desired duration of your cardio workout.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('hands bike', 'cardio', 'body weight', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Adjust the seat height and handlebar position to a comfortable level.', 'Sit on the ergometer with your back straight and feet on the pedals.', 'Grasp the handles with your hands and position your arms at a 90-degree angle.', 'Start pedaling with your hands, pushing and pulling the handles in a controlled motion.', 'Continue pedaling for the desired duration or number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('ski ergometer', 'cardio', 'machine', 'triceps', ARRAY['shoulders', 'forearms'], ARRAY['Adjust the seat height and footrests to a comfortable position.', 'Grasp the handles with an overhand grip, palms facing down.', 'Sit up straight with your feet flat on the footrests.', 'Extend your arms straight out in front of you, keeping your elbows slightly bent.', 'Engage your triceps and push the handles down towards your thighs.', 'Pause for a moment at the bottom, then slowly return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('burpee', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'chest'], ARRAY['Start in a standing position with your feet shoulder-width apart.', 'Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.', 'Kick your feet back into a push-up position.', 'Perform a push-up, keeping your body in a straight line.', 'Jump your feet back into the squat position.', 'Jump up explosively, reaching your arms overhead.', 'Land softly and immediately lower back into a squat position to begin the next repetition.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('mountain climber', 'cardio', 'body weight', 'cardiovascular system', ARRAY['core', 'shoulders', 'triceps'], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line.', 'Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest.', 'Continue alternating legs in a running motion, keeping your hips low and your core engaged.', 'Maintain a steady pace and breathe evenly throughout the exercise.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('jump rope', 'cardio', 'body weight', 'cardiovascular system', ARRAY['calves', 'quadriceps', 'hamstrings', 'glutes'], ARRAY['Hold the handles of the jump rope with your hands, palms facing inward.', 'Stand with your feet shoulder-width apart and knees slightly bent.', 'Swing the rope over your head and jump over it as it comes towards your feet.', 'Land softly on the balls of your feet and repeat the jump as the rope comes around again.', 'Continue jumping for the desired duration or number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('jack burpee', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'triceps', 'core'], ARRAY['Start in a standing position with your feet shoulder-width apart.', 'Lower your body into a squat position, placing your hands on the ground in front of you.', 'Kick your feet back, landing in a push-up position.', 'Perform a push-up, lowering your chest to the ground and then pushing back up.', 'Jump your feet forward, landing in a squat position.', 'Jump up explosively, reaching your arms overhead.', 'Land softly and immediately lower back into the squat position to begin the next repetition.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('jack jump (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'calves'], ARRAY['Stand with your feet together and your arms by your sides.', 'Jump up, spreading your feet apart and raising your arms above your head.', 'As you land, quickly jump back to the starting position.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('star jump (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart and your arms by your sides.', 'Bend your knees slightly and jump up explosively.', 'As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body.', 'Land softly on the balls of your feet with your knees slightly bent.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('high knee against wall', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Stand facing a wall with your feet hip-width apart.', 'Place your hands on the wall for support.', 'Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.', 'Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.', 'Continue alternating legs in a running motion, bringing your knees up as high as possible.', 'Maintain a fast pace and keep your upper body stable throughout the exercise.', 'Repeat for the desired duration or number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('push to run', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start in a push-up position with your hands shoulder-width apart and your body in a straight line.', 'Lower your chest towards the ground by bending your elbows, keeping your body straight.', 'Push through your hands to extend your arms and return to the starting position.', 'Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest.', 'Continue alternating knees as fast as you can while maintaining good form.', 'Continue for the desired duration or number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('bear crawl', 'cardio', 'body weight', 'cardiovascular system', ARRAY['core', 'shoulders', 'triceps'], ARRAY['Start on all fours with your hands directly under your shoulders and your knees directly under your hips.', 'Lift your knees slightly off the ground, keeping your back flat and your core engaged.', 'Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.', 'Continue crawling forward, alternating your hand and foot movements.', 'Maintain a steady pace and keep your core tight throughout the exercise.', 'Continue for the desired distance or time.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('scissor jumps (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Jump off the ground and simultaneously cross your right leg in front of your left leg.', 'As you land, quickly switch legs, crossing your left leg in front of your right leg.', 'Continue alternating legs and jumping as quickly as possible.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('semi squat jump (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees and lower your body into a squat position.', 'Jump explosively, extending your hips and knees while swinging your arms for momentum.', 'Land softly on the balls of your feet and immediately go into the next repetition.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('astride jumps (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees and lower your body into a squat position.', 'Jump explosively upwards, extending your legs and arms.', 'While in the air, spread your legs apart and bring your arms out to the sides.', 'Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('half knee bends (male)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees and lower your body down as if you were sitting back into a chair.', 'Keep your chest up and your weight in your heels.', 'Pause for a moment at the bottom, then push through your heels to return to the starting position.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('quick feet v. 2', 'cardio', 'body weight', 'quads', ARRAY['calves', 'hamstrings'], ARRAY['Stand with your feet shoulder-width apart and your arms by your sides.', 'Begin by rapidly moving your feet up and down, as if you were running in place.', 'Keep your movements quick and light, focusing on staying on the balls of your feet.', 'Continue for the desired duration or number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('short stride run', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Find an open space or a treadmill to perform the exercise.', 'Stand tall with your feet hip-width apart.', 'Start jogging in place, lifting your knees high and pumping your arms.', 'After a few seconds, start taking short strides forward, maintaining a quick pace.', 'Continue running with short strides for the desired duration or distance.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('ski step', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees slightly and keep your back straight.', 'Jump to the right, landing on your right foot while swinging your left leg behind your right leg.', 'Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg.', 'Continue alternating jumps from side to side, mimicking a skiing motion.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('back and forth step', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Step forward with your right foot, bending your knee and lowering your body into a lunge position.', 'Push off with your right foot and step back to the starting position.', 'Repeat the movement with your left foot, alternating legs with each step.', 'Continue stepping back and forth, maintaining a steady pace.', 'Repeat for the desired duration or number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('walking high knees lunge', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Stand with your feet hip-width apart.', 'Lift your right knee up towards your chest as high as you can while balancing on your left leg.', 'Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle.', 'Push off with your right foot and bring your left knee up towards your chest.', 'Step forward with your left foot and lower your body into a lunge position.', 'Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('wind sprints', 'cardio', 'body weight', 'abs', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Find an open space or a track to perform the exercise.', 'Start by standing with your feet shoulder-width apart.', 'Begin running as fast as you can, pumping your arms and driving your knees up.', 'Continue sprinting for a specific distance or time period.', 'Rest and repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('swing 360', 'cardio', 'body weight', 'cardiovascular system', ARRAY['shoulders', 'core'], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.', 'Hold your arms straight out in front of you, parallel to the ground.', 'Engage your core and swing your arms in a circular motion, rotating your torso as you do so.', 'Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions.', 'Remember to breathe throughout the exercise.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('inchworm', 'cardio', 'body weight', 'abs', ARRAY['shoulders', 'hamstrings'], ARRAY['Start in a standing position with your feet hip-width apart.', 'Bend forward at the waist and place your hands on the ground in front of you.', 'Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.', 'Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible.', 'Once your hands reach your feet, stand back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('jump squat', 'cardio', 'body weight', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Lower your body into a squat position by bending your knees and pushing your hips back.', 'Jump explosively off the ground, extending your hips, knees, and ankles.', 'While in mid-air, quickly bring your arms forward for balance.', 'Land softly on the balls of your feet and immediately go into the next repetition.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('jump squat v. 2', 'cardio', 'body weight', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Lower your body into a squat position by bending your knees and pushing your hips back.', 'Jump explosively, extending your hips and knees fully.', 'Land softly on the balls of your feet and immediately lower your body back into a squat position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('forward jump', 'cardio', 'body weight', 'quads', ARRAY['calves', 'hamstrings', 'glutes'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees and lower your body into a squat position.', 'Swing your arms back for momentum.', 'Jump forward explosively, extending your hips, knees, and ankles.', 'Land softly on the balls of your feet and immediately go into the next jump.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('backward jump', 'cardio', 'body weight', 'quads', ARRAY['hamstrings', 'glutes', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees slightly and jump backwards, pushing off with both feet.', 'Land softly on the balls of your feet, bending your knees to absorb the impact.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('bodyweight drop jump squat', 'cardio', 'body weight', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Lower your body into a squat position by bending your knees and pushing your hips back.', 'Jump up explosively, extending your hips, knees, and ankles.', 'While in mid-air, quickly bring your feet together.', 'Land softly on the balls of your feet and immediately drop back into a squat position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lunge with jump', 'cardio', 'body weight', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing with your feet shoulder-width apart.', 'Take a step forward with your right foot, lowering your body into a lunge position.', 'Push off with your right foot and jump into the air, switching the position of your feet mid-air.', 'Land softly with your left foot forward and immediately lower your body into a lunge position.', 'Continue alternating between lunges and jumps for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('skater hops', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'glutes', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Bend your knees slightly and jump to the right, landing on your right foot.', 'As you land, swing your left leg behind your right leg and tap the ground with your left toes.', 'Immediately jump to the left, landing on your left foot.', 'As you land, swing your right leg behind your left leg and tap the ground with your right toes.', 'Continue alternating sides, jumping and tapping the ground with each leg.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('box jump down with one leg stabilization', 'cardio', 'body weight', 'calves', ARRAY['quadriceps', 'hamstrings', 'glutes'], ARRAY['Stand in front of a box or platform with your feet shoulder-width apart.', 'Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.', 'Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.', 'Hold this position for a few seconds, engaging your calf muscles to maintain balance.', 'Slowly step down with the foot that is on the box, returning to the starting position.', 'Repeat the exercise with the other leg.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('battling ropes', 'cardio', 'body weight', 'delts', ARRAY['forearms', 'core'], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.', 'Hold one end of the rope in each hand, with your palms facing each other.', 'Raise your arms to shoulder height, keeping your elbows slightly bent.', 'Begin making alternating waves with the ropes by rapidly raising and lowering each arm.', 'Continue for the desired duration or number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell burpee', 'cardio', 'dumbbell', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves', 'shoulders', 'triceps', 'core'], ARRAY['Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand.', 'Lower your body into a squat position, placing the dumbbells on the ground in front of you.', 'Kick your feet back into a push-up position, keeping your body in a straight line.', 'Perform a push-up, bending your elbows and lowering your chest towards the ground.', 'Jump your feet back towards your hands, landing in a squat position.', 'Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders.', 'Press the dumbbells overhead, fully extending your arms.', 'Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('tire flip', 'cardio', 'body weight', 'glutes', ARRAY['hamstrings', 'quadriceps', 'core'], ARRAY['Stand with your feet shoulder-width apart, facing the tire.', 'Bend your knees and hinge at the hips, lowering into a squat position.', 'Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you.', 'Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground.', 'As the tire flips over, use your upper body strength to guide it and maintain control.', 'Once the tire is fully flipped, quickly step back and reset your stance.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('medicine ball overhead slam', 'cardio', 'body weight', 'upper back', ARRAY['shoulders', 'core'], ARRAY['Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head.', 'Engage your core and keep your back straight.', 'Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you.', 'As you slam the ball down, use your entire body to generate power, including your shoulders and core.', 'Catch the ball on the bounce and repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('sledge hammer', 'cardio', 'body weight', 'abs', ARRAY['forearms', 'shoulders'], ARRAY['Stand with your feet shoulder-width apart and hold the sledge hammer with both hands.', 'Engage your core and keep your back straight.', 'Swing the sledge hammer down towards the ground, using your core and upper body strength.', 'As you swing down, pivot your hips and transfer the force to the hammer.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('flutter kicks', 'cardio', 'body weight', 'glutes', ARRAY['hip flexors', 'lower abs'], ARRAY['Lie flat on your back with your legs extended and your hands by your sides.', 'Engage your core and lift your legs off the ground about 6 inches.', 'Keeping your legs straight, alternate lifting one leg slightly higher than the other.', 'Continue this fluttering motion for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('swimmer kicks v. 2 (male)', 'cardio', 'body weight', 'glutes', ARRAY['hamstrings', 'quadriceps', 'calves'], ARRAY['Lie face down on a mat with your arms extended overhead.', 'Engage your core and lift your chest and legs off the ground simultaneously.', 'Kick your legs up and down in a fluttering motion, as if you were swimming.', 'Continue kicking for the desired number of repetitions.', 'Lower your chest and legs back down to the starting position.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('run (equipment)', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start by standing upright with your feet hip-width apart.', 'Engage your core and keep your upper body relaxed.', 'Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.', 'Maintain a steady pace and continue jogging for the desired duration or distance.', 'Remember to breathe deeply and maintain good posture throughout the exercise.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('kettlebell swing', 'cardio', 'kettlebell', 'glutes', ARRAY['hamstrings', 'core'], ARRAY['Stand with your feet shoulder-width apart, toes pointed slightly outward.', 'Hold the kettlebell with both hands in front of your body, arms extended.', 'Bend your knees slightly and hinge at the hips, pushing your butt back.', 'Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back.', 'Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips.', 'Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('kettlebell thruster', 'cardio', 'kettlebell', 'delts', ARRAY['quadriceps', 'glutes', 'core'], ARRAY['Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other.', 'Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight.', 'As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead.', 'Lock out your arms at the top of the movement, fully extending your elbows.', 'Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('wheel run', 'cardio', 'body weight', 'cardiovascular system', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Start in a plank position with your hands on the wheel and your body straight.', 'Engage your core and start rolling the wheel forward by extending your arms.', 'Continue rolling until your body is fully extended and your arms are overhead.', 'Reverse the movement by pulling the wheel back towards your body, using your core and arms.', 'Repeat for the desired number of repetitions.'], 'distance_duration', NULL, NULL, 'cardio', 'intermediate', false, NULL),
  ('left hook. boxing', 'shoulders', 'body weight', 'delts', ARRAY['biceps', 'triceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.', 'Keep your left hand up to protect your face and your right hand by your chin.', 'Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion.', 'Twist your torso and engage your core muscles to generate power in the punch.', 'Snap your arm back to the starting position and repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('one arm slam (with medicine ball)', 'waist', 'body weight', 'abs', ARRAY['shoulders', 'back'], ARRAY['Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist.', 'Bend your knees slightly and engage your core.', 'Raise the medicine ball above your head, fully extending your arm.', 'Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power.', 'Catch the medicine ball on the bounce and repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL)
ON CONFLICT DO NOTHING;

INSERT INTO exercises (
  name, body_part, equipment, target_muscle,
  secondary_muscles, instructions, exercise_type,
  gif_url, image_url, category, difficulty, is_custom, created_by
) VALUES
  ('cable judo flip', 'waist', 'cable', 'abs', ARRAY['obliques', 'shoulders'], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.', 'Hold the cable handle with both hands at chest level, palms facing down.', 'Engage your core and rotate your torso to the right, pulling the cable across your body.', 'As you rotate, pivot your back foot and allow your hips to rotate naturally.', 'Extend your arms fully and finish the movement by flipping the cable handle over your shoulder.', 'Return to the starting position by reversing the movement, rotating your torso back to the center.', 'Repeat the movement on the opposite side.', 'Continue alternating sides for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
