  ('barbell wide bench press', 'chest', 'barbell', 'pectorals', ARRAY['shoulders', 'triceps'], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.', 'Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.', 'Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.', 'Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.', 'Pause for a moment when the barbell touches your chest, then push it back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell guillotine bench press', 'chest', 'barbell', 'pectorals', ARRAY['shoulders', 'triceps'], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.', 'Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.', 'Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.', 'Pause for a moment when the barbell is just above your neck.', 'Push the barbell back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL)
ON CONFLICT DO NOTHING;

INSERT INTO exercises (
  name, body_part, equipment, target_muscle,
  secondary_muscles, instructions, exercise_type,
  gif_url, image_url, category, difficulty, is_custom, created_by
) VALUES
  ('cable middle fly', 'chest', 'cable', 'pectorals', ARRAY['deltoids', 'triceps'], ARRAY['Attach cables to both sides of a cable machine at chest height.', 'Stand in the center of the machine with one foot slightly in front of the other.', 'Grasp the handles with an overhand grip and extend your arms out to the sides.', 'Keep a slight bend in your elbows and maintain a slight forward lean.', 'Engage your chest muscles and bring your arms forward in a sweeping motion.', 'Pause for a moment at the center, then slowly return your arms back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable incline fly', 'chest', 'cable', 'pectorals', ARRAY['deltoids', 'triceps'], ARRAY['Adjust the cable machine to a low position and attach the handles.', 'Sit on an incline bench with your back against the pad and feet flat on the floor.', 'Grasp the handles with an overhand grip and extend your arms straight out in front of you.', 'Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.', 'Pause for a moment at the fully extended position, then slowly return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable low fly', 'chest', 'cable', 'pectorals', ARRAY['deltoids', 'triceps'], ARRAY['Attach the handles to the low pulleys of a cable machine and select an appropriate weight.', 'Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees.', 'Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows.', 'Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body.', 'Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles.', 'Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell incline fly', 'chest', 'dumbbell', 'pectorals', ARRAY['shoulders'], ARRAY['Set an incline bench to a 45-degree angle.', 'Sit on the bench with a dumbbell in each hand, palms facing each other.', 'Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.', 'Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.', 'Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell decline bench press', 'chest', 'dumbbell', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Lie down on a decline bench with your feet secured and your head lower than your hips.', 'Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward.', 'Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.', 'Push the dumbbells back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell around pullover', 'chest', 'dumbbell', 'pectorals', ARRAY['triceps', 'latissimus dorsi'], ARRAY['Lie flat on a bench with your head at one end and your feet firmly on the ground.', 'Hold a dumbbell with both hands and extend your arms straight above your chest.', 'Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion.', 'Pause for a moment at the bottom, then raise the dumbbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable bench press', 'chest', 'cable', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Adjust the cable machine to chest height and attach the handles.', 'Stand facing away from the machine with your feet shoulder-width apart.', 'Grasp the handles with an overhand grip and step forward to create tension in the cables.', 'Position your feet firmly on the ground and engage your core.', 'Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle.', 'Push the handles forward, extending your arms fully in front of you.', 'Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell lying hammer press', 'chest', 'dumbbell', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.', 'Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.', 'Press the dumbbells back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell incline palm-in press', 'chest', 'dumbbell', 'pectorals', ARRAY['shoulders', 'triceps'], ARRAY['Set up an incline bench at a 45-degree angle.', 'Sit on the bench with a dumbbell in each hand, palms facing each other.', 'Plant your feet firmly on the ground and keep your back straight against the bench.', 'Start with the dumbbells at shoulder level, elbows bent and palms facing each other.', 'Press the dumbbells up and away from your body, extending your arms fully.', 'Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('push-up plus', 'chest', 'body weight', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.', 'Lower your body towards the ground by bending your elbows, keeping them close to your sides.', 'Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up.', 'At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling.', 'Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('isometric chest squeeze', 'chest', 'body weight', 'pectorals', ARRAY['triceps', 'shoulders'], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.', 'Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other.', 'Squeeze your chest muscles together as hard as you can, while keeping your arms straight.', 'Hold this position for a few seconds, focusing on contracting your chest muscles.', 'Release the squeeze and relax your chest muscles.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell reverse grip bent over row', 'back', 'barbell', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.', 'Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.', 'Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.', 'Pull the barbell towards your lower chest, squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower the barbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell pendlay row', 'back', 'barbell', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.', 'Bend forward at the hips, keeping your back straight and your chest up.', 'Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.', 'Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.', 'Lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable bar lateral pulldown', 'back', 'cable', 'lats', ARRAY['biceps', 'rhomboids', 'rear deltoids'], ARRAY['Adjust the cable pulley to a high position and attach a straight bar.', 'Sit facing the cable machine with your feet flat on the ground and your knees slightly bent.', 'Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.', 'Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.', 'Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together.', 'Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable underhand pulldown', 'back', 'cable', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Adjust the cable machine so that the pulldown bar is at a height above your head.', 'Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart.', 'Keep your back straight and lean back slightly.', 'Pull the bar down towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable low seated row', 'back', 'cable', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Sit on the machine with your feet flat on the footrests and your knees slightly bent.', 'Grasp the handles with an overhand grip, palms facing down.', 'Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.', 'Pull the handles towards your body, squeezing your shoulder blades together.', 'Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable seated wide-grip row', 'back', 'cable', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.', 'Grasp the handle with a wide overhand grip, palms facing down.', 'Keep your back straight and lean slightly forward from the hips.', 'Pull the handle towards your lower chest, squeezing your shoulder blades together.', 'Pause for a moment at the peak of the contraction.', 'Slowly release the handle back to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable straight arm pulldown', 'back', 'cable', 'lats', ARRAY['shoulders', 'biceps'], ARRAY['Attach a straight bar to the high pulley of a cable machine.', 'Stand facing the machine with your feet shoulder-width apart.', 'Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.', 'Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement.', 'Pause for a moment at the bottom, then slowly return the bar to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell bent over row', 'back', 'dumbbell', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body.', 'Bend forward at the hips, keeping your back straight and your core engaged.', 'Let your arms hang straight down towards the floor, with your elbows slightly bent.', 'Pull the dumbbells up towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell incline row', 'back', 'dumbbell', 'upper back', ARRAY['biceps', 'shoulders'], ARRAY['Set up an incline bench at a 45-degree angle.', 'Grab a dumbbell in each hand and sit on the bench with your chest against the incline.', 'Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.', 'Pull the dumbbells up towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell bent arm pullover', 'back', 'barbell', 'lats', ARRAY['triceps', 'chest'], ARRAY['Lie flat on a bench with your head at one end and your feet on the floor.', 'Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.', 'Lower the barbell behind your head while keeping your arms slightly bent.', 'Pause for a moment, then raise the barbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell pullover', 'back', 'barbell', 'lats', ARRAY['chest', 'triceps'], ARRAY['Lie flat on a bench with your head at one end and your feet on the floor.', 'Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.', 'Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.', 'Pause for a moment, then raise the barbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('inverted row', 'back', 'body weight', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Set up a bar at waist height or use a suspension trainer.', 'Stand facing the bar or suspension trainer, with your feet shoulder-width apart.', 'Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart.', 'Lean back, keeping your body straight and your heels on the ground.', 'Pull your chest towards the bar or handles, squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower yourself back to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('wide grip pull-up', 'back', 'body weight', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart.', 'Engage your core and squeeze your shoulder blades together.', 'Pull your body up towards the bar until your chin is above the bar.', 'Lower your body back down to the starting position with control.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('close grip chin-up', 'back', 'body weight', 'lats', ARRAY['biceps', 'forearms'], ARRAY['Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart.', 'Hang from the bar with your arms fully extended and your feet off the ground.', 'Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.', 'Continue pulling until your chin is above the bar.', 'Pause for a moment at the top, then slowly lower your body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever t bar row', 'back', 'machine', 'upper back', ARRAY['biceps', 'forearms'], ARRAY['Adjust the seat height and footplate position to ensure proper alignment.', 'Sit on the machine with your chest against the pad and your feet flat on the footplate.', 'Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.', 'Keep your back straight and engage your core.', 'Pull the handles towards your torso, squeezing your shoulder blades together.', 'Pause for a moment at the peak contraction, then slowly release the handles back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell shrug', 'back', 'dumbbell', 'traps', ARRAY['shoulders'], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.', 'Keep your arms straight and let the dumbbells hang by your sides.', 'Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders.', 'Hold the contraction for a second, then slowly lower your shoulders back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell standing bradford press', 'shoulders', 'barbell', 'delts', ARRAY['triceps', 'upper back'], ARRAY['Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.', 'Press the barbell overhead, fully extending your arms.', 'Lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell seated lateral raise', 'shoulders', 'dumbbell', 'delts', ARRAY['traps', 'upper back'], ARRAY['Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.', 'Keep your back straight and core engaged.', 'Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.', 'Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable lateral raise', 'shoulders', 'cable', 'delts', ARRAY['traps', 'triceps'], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip.', 'Keep your arms straight and your core engaged.', 'Raise your arms out to the sides until they are parallel to the floor.', 'Pause for a moment at the top, then slowly lower your arms back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable rear delt row (with rope)', 'shoulders', 'cable', 'delts', ARRAY['trapezius', 'rhomboids', 'biceps'], ARRAY['Attach a rope handle to a low pulley cable machine.', 'Stand facing the machine with your feet shoulder-width apart.', 'Grasp the rope handle with an overhand grip, palms facing each other.', 'Bend your knees slightly and hinge forward at the hips, keeping your back straight.', 'Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable front raise', 'shoulders', 'cable', 'delts', ARRAY['triceps', 'forearms'], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.', 'Keep your back straight and your core engaged.', 'Raise the cable handle in front of you, keeping your arms straight and your palms facing down.', 'Continue lifting until your arms are parallel to the floor.', 'Pause for a moment at the top, then slowly lower the cable handle back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell lying rear lateral raise', 'shoulders', 'dumbbell', 'delts', ARRAY['traps', 'rhomboids'], ARRAY['Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.', 'Extend your arms straight down towards the floor, keeping a slight bend in your elbows.', 'Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.', 'Pause for a moment at the top, then slowly lower your arms back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell one arm lateral raise', 'shoulders', 'dumbbell', 'delts', ARRAY['trapezius', 'triceps'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.', 'Keep your back straight and your core engaged throughout the exercise.', 'Raise the dumbbell to the side, keeping your arm straight and your palm facing down.', 'Continue lifting until your arm is parallel to the ground.', 'Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.', 'Repeat for the desired number of repetitions, then switch to the other arm.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever military press', 'shoulders', 'machine', 'delts', ARRAY['triceps', 'upper chest'], ARRAY['Adjust the seat height and position yourself on the machine with your back against the backrest.', 'Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.', 'Push the handles upward until your arms are fully extended, but do not lock your elbows.', 'Pause for a moment at the top, then slowly lower the handles back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell seated shoulder press', 'shoulders', 'dumbbell', 'delts', ARRAY['triceps', 'upper back'], ARRAY['Sit on a bench with a dumbbell in each hand, resting on your thighs.', 'Raise the dumbbells to shoulder height, palms facing forward.', 'Press the dumbbells upward until your arms are fully extended overhead.', 'Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell standing wide military press', 'shoulders', 'barbell', 'delts', ARRAY['triceps', 'upper back'], ARRAY['Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.', 'Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.', 'Press the barbell overhead, extending your arms fully.', 'Lower the barbell back to shoulder height and repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell rear delt row', 'shoulders', 'barbell', 'delts', ARRAY['trapezius', 'rhomboids', 'biceps'], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.', 'Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.', 'Bend forward at the hips, keeping your back straight and chest up.', 'Pull the barbell towards your chest, squeezing your shoulder blades together.', 'Pause for a moment at the top, then slowly lower the barbell back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell standing front raise above head', 'shoulders', 'dumbbell', 'delts', ARRAY['trapezius', 'biceps'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.', 'Keep your arms straight and lift the dumbbells in front of you, raising them above your head.', 'Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('ez barbell curl', 'upper arms', 'ez barbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.', 'Keep your elbows close to your torso and your upper arms stationary throughout the movement.', 'Exhale as you curl the barbell up towards your shoulders, contracting your biceps.', 'Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('ez barbell close-grip curl', 'upper arms', 'ez barbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands shoulder-width apart.', 'Keep your elbows close to your torso and your upper arms stationary throughout the movement.', 'Curl the barbell up towards your shoulders, contracting your biceps.', 'Pause for a moment at the top, then slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell preacher curl', 'upper arms', 'barbell', 'biceps', ARRAY['forearms'], ARRAY['Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.', 'Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.', 'Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.', 'Pause for a moment at the top, squeezing your biceps.', 'Inhale and slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable one arm curl', 'upper arms', 'cable', 'biceps', ARRAY['forearms'], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.', 'Grasp the cable handle with an underhand grip, palm facing up.', 'Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.', 'Pause for a moment at the top, then slowly lower your forearm back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable curl', 'upper arms', 'cable', 'biceps', ARRAY['forearms'], ARRAY['Stand facing the cable machine with your feet shoulder-width apart.', 'Grasp the cable attachment with an underhand grip, palms facing up.', 'Keep your elbows close to your sides and your upper arms stationary.', 'Exhale and curl the cable attachment towards your shoulders, contracting your biceps.', 'Pause for a moment at the top of the movement, squeezing your biceps.', 'Inhale and slowly lower the cable attachment back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell incline biceps curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.', 'Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly begin to lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell seated bicep curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.', 'Keep your back straight and your elbows close to your torso.', 'Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.', 'Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell alternate biceps curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.', 'Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly begin to lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions, alternating arms.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell prone incline curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Adjust the bench to a 45-degree incline.', 'Lie face down on the bench with your chest and stomach resting against it.', 'Hold a dumbbell in each hand with your palms facing down and your arms fully extended.', 'Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly begin to lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable hammer curl (with rope)', 'upper arms', 'cable', 'biceps', ARRAY['forearms'], ARRAY['Stand upright with your feet shoulder-width apart and a slight bend in your knees.', 'Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended.', 'Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.', 'Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale and slowly begin to lower the cable rope attachment back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell reverse curl', 'upper arms', 'barbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.', 'Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.', 'Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.', 'Hold the contracted position for a brief pause as you squeeze your biceps.', 'Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL)
ON CONFLICT DO NOTHING;

INSERT INTO exercises (
  name, body_part, equipment, target_muscle,
  secondary_muscles, instructions, exercise_type,
  gif_url, image_url, category, difficulty, is_custom, created_by
) VALUES
  ('dumbbell zottman curl', 'upper arms', 'dumbbell', 'biceps', ARRAY['forearms'], ARRAY['Stand up straight with a dumbbell in each hand, palms facing your body.', 'Keep your elbows close to your torso and rotate your palms to face forward.', 'Curl the dumbbells up to your shoulders while keeping your upper arms stationary.', 'At the top of the movement, rotate your wrists so that your palms are facing away from your body.', 'Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell close-grip bench press', 'upper arms', 'barbell', 'triceps', ARRAY['chest', 'shoulders'], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.', 'Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.', 'Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.', 'Pause for a moment when the barbell touches your chest.', 'Push the barbell back up to the starting position, fully extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable lying triceps extension v. 2', 'upper arms', 'cable', 'triceps', ARRAY['shoulders'], ARRAY['Attach a rope handle to a low pulley cable machine.', 'Lie down on a flat bench facing up, with your head towards the cable machine.', 'Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest.', 'Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows.', 'Pause for a moment at the bottom, then extend your arms back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable overhead triceps extension (rope attachment)', 'upper arms', 'cable', 'triceps', ARRAY['shoulders'], ARRAY['Attach a rope to a cable machine at a high position.', 'Stand facing away from the machine with your feet shoulder-width apart.', 'Grasp the rope with both hands, palms facing each other, and bring your hands above your head.', 'Keep your upper arms close to your head and your elbows pointing forward.', 'Slowly lower the rope behind your head by bending your elbows.', 'Pause for a moment, then extend your arms back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell lying triceps extension', 'upper arms', 'dumbbell', 'triceps', ARRAY['shoulders'], ARRAY['Lie flat on a bench with a dumbbell in each hand, palms facing each other.', 'Extend your arms straight up over your chest, keeping your elbows close to your body.', 'Lower the dumbbells down towards your forehead, bending your elbows.', 'Pause for a moment, then extend your arms back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell seated bench extension', 'upper arms', 'dumbbell', 'triceps', ARRAY['shoulders'], ARRAY['Sit on a bench with your back straight and feet flat on the ground.', 'Hold a dumbbell with both hands and extend your arms straight up above your head.', 'Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.', 'Pause for a moment, then raise the dumbbell back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell kickback', 'upper arms', 'dumbbell', 'triceps', ARRAY['shoulders'], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.', 'Bend your knees slightly and hinge forward at the hips, keeping your back straight.', 'Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.', 'Extend your arms straight back, squeezing your triceps at the top of the movement.', 'Pause for a moment, then slowly lower the dumbbells back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell lying close-grip triceps extension', 'upper arms', 'barbell', 'triceps', ARRAY['shoulders'], ARRAY['Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.', 'Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.', 'Extend your arms fully, lifting the barbell above your chest.', 'Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.', 'Pause for a moment at the bottom, then extend your arms back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('ez barbell seated triceps extension', 'upper arms', 'ez barbell', 'triceps', ARRAY['shoulders'], ARRAY['Sit on a bench with your back straight and feet flat on the ground.', 'Hold the ez barbell with an overhand grip, hands shoulder-width apart.', 'Raise the barbell overhead, fully extending your arms.', 'Keeping your upper arms stationary, lower the barbell behind your head by bending your elbows.', 'Pause for a moment, then raise the barbell back to the starting position by extending your arms.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell one arm triceps extension (on bench)', 'upper arms', 'dumbbell', 'triceps', ARRAY['shoulders'], ARRAY['Sit on a bench with your back straight and feet flat on the ground.', 'Hold a dumbbell in one hand and place your other hand on the bench for support.', 'Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward.', 'Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.', 'Extend your arm back up to the starting position, fully straightening your elbow.', 'Repeat for the desired number of repetitions, then switch arms.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable one arm tricep pushdown', 'upper arms', 'cable', 'triceps', ARRAY['forearms'], ARRAY['Stand facing a cable machine with a straight bar attachment at chest height.', 'Grasp the bar with an overhand grip and step back to create tension in the cable.', 'Position your feet shoulder-width apart and slightly bend your knees.', 'Keep your back straight and core engaged throughout the exercise.', 'Start with your arm fully extended and perpendicular to the floor.', 'Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended.', 'Pause for a moment, then inhale and slowly return to the starting position.', 'Repeat for the desired number of repetitions, then switch arms.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('diamond push-up', 'upper arms', 'body weight', 'triceps', ARRAY['chest', 'shoulders'], ARRAY['Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers.', 'Keep your body in a straight line from head to toe, engaging your core and glutes.', 'Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body.', 'Pause for a moment at the bottom, then push yourself back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('bench dip (knees bent)', 'upper arms', 'body weight', 'triceps', ARRAY['chest', 'shoulders'], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.', 'Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.', 'Bend your elbows and lower your body towards the ground, keeping your back close to the bench.', 'Pause for a moment at the bottom, then push yourself back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell front squat', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves', 'core'], ARRAY['Start by standing with your feet shoulder-width apart, toes slightly turned out.', 'Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.', 'Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.', 'Lower until your thighs are parallel to the ground, or as low as you can comfortably go.', 'Pause for a moment at the bottom, then push through your heels to return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell speed squat', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart, toes slightly turned out.', 'Hold the barbell across your upper back, resting it on your traps or rear delts.', 'Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.', 'Lower until your thighs are parallel to the ground, or as low as you can comfortably go.', 'Drive through your heels to stand back up, squeezing your glutes at the top.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell goblet squat', 'upper legs', 'dumbbell', 'quads', ARRAY['glutes', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.', 'Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.', 'Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.', 'Pause for a moment at the bottom, then push through your heels to return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell lunge', 'upper legs', 'dumbbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.', 'Take a step forward with your right foot, lowering your body into a lunge position.', 'Keep your back straight and your chest up as you lower your body.', 'Push through your right heel to return to the starting position.', 'Repeat with your left leg.', 'Alternate legs for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('walking lunge', 'upper legs', 'body weight', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Take a step forward with your right leg, lowering your body into a lunge position.', 'Keep your torso upright and your front knee aligned with your ankle.', 'Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg.', 'Continue alternating legs and walking forward, maintaining a controlled and steady pace.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('split squats', 'upper legs', 'body weight', 'quads', ARRAY['glutes', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart.', 'Take a step forward with one foot and place it about two feet in front of the other foot.', 'Lower your body by bending your knees and hips, keeping your back straight.', 'Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground.', 'Pause for a moment, then push through your front heel to return to the starting position.', 'Repeat for the desired number of repetitions, then switch legs and repeat.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell lateral lunge', 'upper legs', 'barbell', 'glutes', ARRAY['quadriceps', 'hamstrings', 'calves'], ARRAY['Stand with your feet shoulder-width apart, holding a barbell across your upper back.', 'Take a big step to the side with your right foot, keeping your left foot planted.', 'Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.', 'Push off with your right foot and return to the starting position.', 'Repeat on the other side, stepping with your left foot.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell good morning', 'upper legs', 'barbell', 'hamstrings', ARRAY['lower back'], ARRAY['Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.', 'Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.', 'Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.', 'Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell stiff leg deadlift', 'upper legs', 'dumbbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.', 'Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees.', 'Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever seated leg curl', 'upper legs', 'machine', 'hamstrings', ARRAY['calves'], ARRAY['Adjust the machine to fit your body and sit on it with your back against the backrest.', 'Place your lower legs under the padded lever, just above your ankles.', 'Grasp the handles on the sides of the machine for support.', 'Keeping your upper legs stationary, exhale and curl your legs up as far as possible.', 'Hold the contracted position for a brief pause as you squeeze your hamstrings.', 'Inhale and slowly lower the lever back to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('glute-ham raise', 'upper legs', 'body weight', 'hamstrings', ARRAY['glutes', 'lower back'], ARRAY['Adjust the glute-ham raise machine to fit your body.', 'Position yourself face down on the machine with your ankles secured.', 'Place your hands on your chest or cross them over your chest.', 'Engage your hamstrings and glutes to lift your upper body up towards the ceiling.', 'Continue lifting until your body is in a straight line from your head to your heels.', 'Pause for a moment at the top, then slowly lower your body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell glute bridge', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.', 'Place a barbell across your hips, holding it securely with both hands.', 'Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.', 'Pause for a moment at the top, squeezing your glutes.', 'Slowly lower your hips back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell single leg deadlift', 'upper legs', 'dumbbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Stand with your feet hip-width apart, holding a dumbbell in your right hand.', 'Shift your weight onto your left leg and lift your right foot slightly off the ground.', 'Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.', 'At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.', 'Lower the dumbbell until your torso and right leg are parallel to the ground.', 'Pause for a moment, then engage your glutes and hamstrings to return to the starting position.', 'Repeat for the desired number of repetitions, then switch sides.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('glute bridge two legs on bench (male)', 'upper legs', 'body weight', 'glutes', ARRAY['hamstrings', 'core'], ARRAY['Sit on the edge of a bench with your back against it and your feet flat on the ground.', 'Place your hands on the bench beside your hips for support.', 'Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.', 'Pause for a moment at the top, then slowly lower your hips back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell rack pull', 'upper legs', 'barbell', 'glutes', ARRAY['hamstrings', 'lower back'], ARRAY['Set up a barbell on a rack at knee height.', 'Stand with your feet shoulder-width apart, toes pointing slightly outwards.', 'Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.', 'Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.', 'Lower the barbell back down to the starting position by bending at the hips and knees.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell standing calf raise', 'lower legs', 'barbell', 'calves', ARRAY['hamstrings', 'glutes'], ARRAY['Stand with your feet shoulder-width apart and place a barbell across your upper back.', 'Raise your heels off the ground as high as possible, using only your toes.', 'Pause for a moment at the top, then slowly lower your heels back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell standing calf raise', 'lower legs', 'dumbbell', 'calves', ARRAY['ankles'], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand.', 'Raise your heels off the ground as high as possible, using your calves.', 'Pause for a moment at the top, then slowly lower your heels back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('lever seated calf raise', 'lower legs', 'machine', 'calves', ARRAY['soleus', 'ankle stabilizers'], ARRAY['Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.', 'Place your toes on the footplate with your heels hanging off the edge.', 'Grasp the handles or the sides of the seat for stability.', 'Push through the balls of your feet to raise your heels as high as possible.', 'Pause for a moment at the top, then slowly lower your heels back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('donkey calf raise', 'lower legs', 'body weight', 'calves', ARRAY['hamstrings', 'glutes'], ARRAY['Stand with your toes on an elevated surface, such as a step or block.', 'Place your hands on a stable support, such as a wall or railing, for balance.', 'Raise your heels as high as possible, lifting your body weight onto the balls of your feet.', 'Pause for a moment at the top, then slowly lower your heels back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('single leg calf raise (on a dumbbell)', 'lower legs', 'dumbbell', 'calves', ARRAY['ankles', 'feet'], ARRAY['Stand with your feet hip-width apart and hold a dumbbell in one hand.', 'Lift one foot off the ground and balance on the other foot.', 'Slowly raise your heel as high as possible, using your calf muscles.', 'Pause for a moment at the top, then slowly lower your heel back down.', 'Repeat for the desired number of repetitions, then switch to the other leg.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cross body crunch', 'waist', 'body weight', 'abs', ARRAY['obliques'], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.', 'Place your hands behind your head with your elbows pointing outwards.', 'Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee.', 'Pause for a moment at the top, then slowly lower your upper body back down to the starting position.', 'Repeat on the other side, bringing your left elbow towards your right knee.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('jackknife sit-up', 'waist', 'body weight', 'abs', ARRAY['hip flexors'], ARRAY['Lie flat on your back with your legs extended and your arms overhead.', 'Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes.', 'Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('hanging oblique knee raise', 'waist', 'body weight', 'abs', ARRAY['obliques'], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.', 'Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so.', 'Pause for a moment at the top, then slowly lower your legs back down to the starting position.', 'Repeat on the other side, twisting your torso in the opposite direction.', 'Continue alternating sides for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable twist', 'waist', 'cable', 'abs', ARRAY['obliques'], ARRAY['Stand with your feet shoulder-width apart, facing the cable machine.', 'Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.', 'Engage your core and twist your torso to the right, pulling the cable across your body.', 'Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques.', 'Slowly return to the starting position, resisting the cable''s pull.', 'Repeat the movement to the left side.', 'Continue alternating sides for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('wheel rollerout', 'waist', 'body weight', 'abs', ARRAY['lower back'], ARRAY['Kneel on the floor and place the wheel roller in front of you.', 'Place your hands on the handles of the wheel roller and extend your arms straight out in front of you.', 'Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight.', 'Continue rolling forward until your body is fully extended and your arms are overhead.', 'Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('cable side bend', 'waist', 'cable', 'abs', ARRAY['obliques'], ARRAY['Stand with your feet shoulder-width apart and grasp the cable handle with one hand.', 'Keep your back straight and your core engaged.', 'Slowly bend sideways at the waist, lowering the cable handle towards your knee.', 'Pause for a moment, then return to the starting position.', 'Repeat on the other side.', 'Alternate sides for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell rollerout', 'waist', 'barbell', 'abs', ARRAY['lower back'], ARRAY['Kneel on the floor and hold a barbell with both hands, shoulder-width apart.', 'Roll the barbell forward, extending your arms and keeping your core engaged.', 'Continue rolling forward until your body is fully extended and your arms are overhead.', 'Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('tuck crunch', 'waist', 'body weight', 'abs', ARRAY['hip flexors'], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.', 'Place your hands behind your head with your elbows pointing outwards.', 'Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees.', 'Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('suspended abdominal fallout', 'waist', 'body weight', 'abs', ARRAY['obliques', 'hip flexors'], ARRAY['Attach a suspension trainer to a high anchor point and adjust the straps to waist height.', 'Stand facing away from the anchor point and hold the handles with your arms extended in front of you.', 'Lean forward at the waist, keeping your body straight and your core engaged.', 'Lower your body as far as you can while maintaining control and tension in your abs.', 'Pause for a moment at the bottom, then slowly raise your body back up to the starting position.', 'Repeat for the desired number of repetitions.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('oblique crunches floor', 'waist', 'body weight', 'abs', ARRAY['obliques'], ARRAY['Lie on your back with your knees bent and feet flat on the floor.', 'Place your hands behind your head or cross them over your chest.', 'Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side.', 'Pause for a moment, then lower your shoulder blades back down to the floor.', 'Repeat on the other side, alternating sides with each repetition.'], 'bodyweight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell wrist curl', 'lower arms', 'barbell', 'forearms', ARRAY['biceps', 'brachialis'], ARRAY['Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.', 'Allow the barbell to roll down to your fingertips, keeping your wrists straight.', 'Slowly curl the barbell up towards your forearms by flexing your wrists.', 'Pause for a moment at the top, then slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('barbell reverse wrist curl', 'lower arms', 'barbell', 'forearms', ARRAY['biceps', 'brachialis'], ARRAY['Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.', 'Rest your forearms on your thighs, allowing your wrists to hang off the edge.', 'Slowly curl your wrists upward, bringing the barbell towards your body.', 'Pause for a moment at the top, then slowly lower the barbell back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
  ('dumbbell seated palms up wrist curl', 'lower arms', 'dumbbell', 'forearms', ARRAY['biceps', 'shoulders'], ARRAY['Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.', 'Rest your forearms on your thighs, allowing your wrists to hang off the edge.', 'Slowly curl your wrists upward, squeezing your forearms at the top of the movement.', 'Pause for a moment, then lower your wrists back down to the starting position.', 'Repeat for the desired number of repetitions.'], 'weight_reps', NULL, NULL, 'strength', 'intermediate', false, NULL),
